#include <stdio.h>
#include <limits.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int f[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &f[i]);
        }
        int assistants = 0;
        int cooked[N];
        for (int i = 0; i < N; i++) {
            cooked[i] = 0;
        }
        while (1) {
            int min_time = INT_MAX;
            int min_index = -1;
            for (int i = 0; i < N; i++) {
                if (!cooked[i] && f[i] < min_time) {
                    min_time = f[i];
                    min_index = i;
                }
            }
            if (min_index == -1) {
                break;
            }
            assistants++;
            for (int i = max(0, min_index - K + 1); i <= min(min_index + K - 1, N - 1); i++) {
                if (f[i] == min_time) {
                    cooked[i] = 1;
                }
            }
        }
        printf("%d\n", assistants);
    }
    return 0;
}

