import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] f = new int[N];
            for (int i = 0; i < N; i++) {
                f[i] = sc.nextInt();
            }
            int assistants = 0;
            boolean[] cooked = new boolean[N];
            while (true) {
                int min_time = Integer.MAX_VALUE;
                int min_index = -1;
                for (int i = 0; i < N; i++) {
                    if (!cooked[i] && f[i] < min_time) {
                        min_time = f[i];
                        min_index = i;
                    }
                }
                if (min_index == -1) {
                    break;
                }
                assistants++;
                for (int i = Math.max(0, min_index - K + 1); i <= Math.min(min_index + K - 1, N - 1); i++) {
                    if (f[i] == min_time) {
                        cooked[i] = true;
                    }
                }
            }
            System.out.println(assistants);
        }
    }
}

